+// ── Doctor Fix ────────────────────────────────────────────────────────
+
+/// Fixable check IDs and their remediation logic.
+const FIXABLE_CHECKS: &[&str] = &[
+    "legacy_python_alias",
+    "path_order",
+    "mcp_config",
+    "storage_root_git_index_lock",
+    "guard_hooks",
+    "wal_mode",
+];
